<?php
if ( ! current_user_can( 'creditrack_manage_users' ) ) { wp_die( 'Access denied.', '', array( 'response' => 403 ) ); }
$users = get_users( array( 'number' => 100, 'orderby' => 'display_name', 'role__in' => array( 'creditrack_administrator','creditrack_loan_officer','creditrack_viewer' ) ) ); $edit_id = absint( $_GET['user_id'] ?? 0 ); $editing = $edit_id ? get_userdata( $edit_id ) : null;
?><div class="ct-titlebar"><div><h1>Users</h1><div class="ct-muted">Roles, account state, and secure password resets.</div></div><a class="ct-button" href="#user-form">Add user</a></div><div class="ct-table-wrap"><table><thead><tr><th>Name</th><th>Email</th><th>Role</th><th>Last login</th><th>Status</th><th>Actions</th></tr></thead><tbody><?php foreach ( $users as $item ) { $active = '0' !== (string) get_user_meta( $item->ID, 'creditrack_active', true ); ?><tr><td><?php echo esc_html( $item->display_name ); ?></td><td><?php echo esc_html( $item->user_email ); ?></td><td><?php echo esc_html( implode( ', ', $item->roles ) ); ?></td><td><?php echo esc_html( get_user_meta( $item->ID, 'creditrack_last_login', true ) ?: 'Never' ); ?></td><td><span class="ct-badge <?php echo $active ? 'Active' : ''; ?>"><?php echo $active ? 'Active' : 'Inactive'; ?></span></td><td><div class="ct-actions"><a class="ct-button secondary" href="<?php echo esc_url( add_query_arg( 'user_id', $item->ID, $base . 'users/#user-form' ) ); ?>">Edit</a><form method="post" action="<?php echo esc_url( admin_url( 'admin-post.php' ) ); ?>"><?php wp_nonce_field( 'creditrack_action' ); ?><input type="hidden" name="action" value="creditrack_send_password_reset"><input type="hidden" name="user_id" value="<?php echo esc_attr( $item->ID ); ?>"><button type="submit">Send reset link</button></form></div></td></tr><?php } ?></tbody></table></div>
<section id="user-form" class="ct-card"><h2><?php echo $editing ? 'Edit user' : 'Add user'; ?></h2><form class="ct-form" method="post" action="<?php echo esc_url( admin_url( 'admin-post.php' ) ); ?>"><?php wp_nonce_field( 'creditrack_action' ); ?><input type="hidden" name="action" value="creditrack_save_user"><input type="hidden" name="user_id" value="<?php echo esc_attr( $editing->ID ?? 0 ); ?>"><div class="ct-field"><label for="user_first_name">First name</label><input id="user_first_name" name="first_name" value="<?php echo esc_attr( $editing->first_name ?? '' ); ?>" required></div><div class="ct-field"><label for="user_last_name">Last name</label><input id="user_last_name" name="last_name" value="<?php echo esc_attr( $editing->last_name ?? '' ); ?>" required></div><div class="ct-field"><label for="user_email">Email</label><input id="user_email" type="email" name="email" value="<?php echo esc_attr( $editing->user_email ?? '' ); ?>" required></div><div class="ct-field"><label for="role">Role</label><select id="role" name="role"><?php foreach ( array( 'creditrack_administrator'=>'CrediTrack Administrator','creditrack_loan_officer'=>'Loan Officer','creditrack_viewer'=>'Viewer' ) as $role => $label ) { ?><option value="<?php echo esc_attr( $role ); ?>" <?php selected( $editing && in_array( $role, $editing->roles, true ) ); ?>><?php echo esc_html( $label ); ?></option><?php } ?></select></div><div class="ct-field full"><label><input type="checkbox" name="is_active" value="1" <?php checked( ! $editing || '0' !== (string) get_user_meta( $editing->ID, 'creditrack_active', true ) ); ?>> Active account</label></div><div><button type="submit">Save user</button></div></form></section>
